# Automatic retry on validation failure
max_retries = 3
for attempt in range(max_retries):
    try:
        result = llm.generate(prompt)
        validated = schema.validate(result)
        return validated
    except ValidationError:
        prompt = adjust_prompt(prompt, error)
        continue

