# clean() handles missing values gracefully
df = pl.DataFrame({
    "weight": ["5kg", None, "3kg", ""]
})
result = loclean.clean(
    df,
    target_col="weight",
    instruction="Extract weight value and unit"
)
Note: Missing values result in None for clean_value, clean_unit, and clean_reasoning.
